# Regulator Match Functions
# ------------------------------------------------------------------------------------------------------

def gen_match046(result, opp):
    match = None

    std_body_labels046 = {
        'R046134': '3/4"',
        'R046110': '1"',
        'R04611Q': '1-1/4"',
    }

    irv_body_labels046 = {
        'R046234': '3/4"',
        'R046210': '1"',
        'R04621Q': '1-1/4"',
    }

    std_pipe_priority = {
        '3/4"': 'R046134',
        '1"':    'R046110',
        '1-1/4"': 'R04611Q',
    }

    irv_pipe_priority = {
        '3/4"': 'R046234',
        '1"':    'R046210',
        '1-1/4"': 'R04621Q',
    }

    all_std_prefixes = list(std_body_labels046.keys())
    prioritized_std = std_pipe_priority.get(pipesize_input)
    if prioritized_std:
        ordered_std_prefixes = [prioritized_std] + [p for p in all_std_prefixes if p != prioritized_std]
    else:
        ordered_std_prefixes = all_std_prefixes

    all_irv_prefixes = list(irv_body_labels046.keys())
    prioritized_irv = irv_pipe_priority.get(pipesize_input)
    if prioritized_irv:
        ordered_irv_prefixes = [prioritized_irv] + [p for p in all_irv_prefixes if p != prioritized_irv]
    else:
        ordered_irv_prefixes = all_irv_prefixes

    orifice_order = ['12', '38', '56', '14', '36', '18']

    #seat logic
    diff = inlet_input - outlet_input
    seat = 'Poly-Tan'
    if maop < 600 and diff < 400:
        seat = 'Poly-Tan'

    # IRV sizing
    if opp == "IRV":
        for prefix in ordered_irv_prefixes:
            for orifice in orifice_order:
                reg = f"{prefix}_{orifice}"
                if reg in result:
                    cap = result[reg]
                    if will_work(cap, reg, orifice_max046(reg)) == "Yes" and will_irv_work046(reg, irv_input) != "No":
                        match = {
                            'reg' : reg,
                            'model': '046-2',
                            'diap': None,
                            'body': irv_body_labels046[prefix],
                            'orifice': orifice_typeSMALL(reg),
                            'seat': seat,
                            'color': spring_046(outlet_input)['color'],
                            'range': spring_046(outlet_input)['range'],
                            'capacity': cap,
                            'opp': "IRV",
                        }
                        return match
    # STD sizing
    else:
        for prefix in ordered_std_prefixes:
            for orifice in orifice_order:
                reg = f"{prefix}_{orifice}"
                if reg in result:
                    cap = result[reg]
                    if will_work(cap, reg, orifice_max046(reg)) == "Yes":
                        match = {
                            'reg' : reg,
                            'model': '046',
                            'diap': None,
                            'body': std_body_labels046[prefix],
                            'orifice': orifice_typeSMALL(reg),
                            'seat': seat,
                            'color': spring_046(outlet_input)['color'],
                            'range': spring_046(outlet_input)['range'],
                            'capacity': cap,
                            'opp': opp,
                        }
                        return match

def run_regulator_selection046(inlet, outlet, opp):

    warning = None

    if opp == "IRV" and not partial:
        result = interpolate_capacity(data046, inlet, outlet, False, False)

        if isinstance(result, str):
            warning = result
            result = None
            match = None
            apply = False
            return result, match, apply, warning

        # Try with IRV
        match = gen_match046(result, opp)

        if match:
            apply = True
            warning = "Sized with IRV"
        # IRV does not work- try with Monitor
        else:
            result = interpolate_capacity(data046, inlet, outlet, True, False)
            if isinstance(result, str):
                warning = result
                result = None
                match = None
                apply = False
                return result, match, apply, warning
            
            match = gen_match046(result, "Monitor")

            if match:
                apply = True
                warning = "IRV curves did not work for your application, sized for worker/monitor setup"
            else:
                apply = False

    # Monitor or no overpressure protection or partial IRV
    else:
        if opp == "Monitor":
            result = interpolate_capacity(data046, inlet, outlet, True, False)
        else:
            result = interpolate_capacity(data046, inlet, outlet, False, False)
        
        if isinstance(result, str):
                warning = result
                result = None
                match = None
                apply = False
                return result, match, apply, warning
        
        match = gen_match046(result, opp)

        if match:
            apply = True
            if opp == "Monitor":
                warning = "Sized for worker/monitor setup"
        else:
            apply = False
    
    return result, match, apply, warning


# Part Number Configurator
# ------------------------------------------------------------------------------------------------------

def hsc_pnc046(match):
    body_map = {
        '3/4"': '3/4',
        '1"': '1',
        '1-1/4"': '1-1/4',
    }
    orifice_map = {
        '1/8"': "10",
        '3/16"': "11",
        '1/4"': "12",
        '5/16"': "13",
        '3/8"': "14",
        '1/2"': "15",
    }
    spring_map = {
        'Yellow': '23',
        'Aluminum': '24',
        'White': '25',
        'Green': '28',
        'Tan': '26',
        'Gray': '27',
    }

    model = match['model']
    body = body_map.get(match['body'])
    orifice = orifice_map.get(match['orifice'])
    seat = 'TAN' # NetSuite only uses TAN orifice on most models
    spring = spring_map.get(match['color'])

    if model == '046-2':
        return f"R.046-2.IRV.{body}.IRV.{orifice}.{seat}.{spring}.ALU"
    elif model == '046' and match['opp'] != "Monitor":
        return f"R.046-1.STD.{body}.{orifice}.{seat}.{spring}.ALU"
    # Under 125 psi setpoint - use 046-2M for monitor
    elif spring != '27':
        return [
            f"R.046-2M.MON.{body}.IRV.{orifice}.{seat}.{spring}.ALU",
            f"R.046-1.STD.{body}.{orifice}.{seat}.{spring}.ALU",
        ]
    # over 125 psi setpoint - use 046-M for monitor
    else:
        return [
            f"R.046-M.MON.{body}.{orifice}.{seat}.{spring}.ALU",
            f"R.046-1.STD.{body}.{orifice}.{seat}.{spring}.ALU",
        ]


# Output Functions
# ------------------------------------------------------------------------------------------------------

def print_model_table(title, prefix, opp, result):
    if opp == "IRV" and not partial:
        rows = [
            [orifice_typeSMALL(reg), f"{cap:,.0f}" if isinstance(cap, (int, float)) else cap, will_work(cap, reg, orifice_max046(reg)), will_irv_work046(reg, irv_input)]
            for reg, cap in result.items()
            if reg.startswith(prefix)
        ]
        print("\n" + title)
        print(tabulate(rows, headers=["Orifice Size", "Calculated Capacity (CFH)", "Will Reg Work?", "Will IRV Work?"], tablefmt="simple_grid"))
    else:
        rows = [
            [orifice_typeSMALL(reg), f"{cap:,.0f}" if isinstance(cap, (int, float)) else cap, will_work(cap, reg, orifice_max046(reg))]
            for reg, cap in result.items()
            if reg.startswith(prefix)
        ]
        print("\n" + title)
        print(tabulate(rows, headers=["Orifice Size", "Calculated Capacity (CFH)", "Will It Work?"], tablefmt="simple_grid"))

def print_regulator_selection(match):
    print("REGULATOR SELECTION")
    print(f"Model:", match['model'])
    if match['diap'] != None:
        print(f"Diaphragm Size:", match['diap'])
    print(f"Body Size:", match['body'])
    if match['orifice'] != None:
        print(f"Orifice Size:", match['orifice'])
    if match['seat'] != None:
        print(f"Seat:", match['seat'])
    print(f"Spring:", match['color'], match['range'])
    capacity = match['capacity']
    cap_str = f"{capacity:,.0f}" if isinstance(capacity, (int, float)) else str(capacity)
    print(f"Calculated Capacity (CFH): {cap_str}")

    print("")
    print("Sizing Adjustments")
    if match['opp'] == "Monitor":
        print("Monitor regulator: 30% Capacity reduction")
    print(f"Oversized by {oversize_percent:.0f}%")
    if gastypemult != 1:
        print(f"Multiplier for other gas: {gastypemult}")

# INPUT
# ------------------------------------------------------------------------------------------------------

print("Model 046 Sizing Tool")

inlet_units = input("Inlet Pressure units (psi, bar): ")
inlet_input = float(input("Enter inlet pressure: "))

outlet_units = input("Outlet Pressure units (in wc, psi, bar): ")
outlet_input = float(input("Enter outlet pressure: "))

flowrate_units = input("Gas Load units (CFH, BTUH, CMH): ")
flow_rate = float(input("Enter gas load/flow rate: "))

maop = float(input("MAOP (psi): "))
maop = inlet_input if maop == 0 else maop

pipesize_input = (input("Enter desired pipe size (enter N/A, 0.75, 1, 1.25, ect.): "))
pipesize_input = 0 if pipesize_input == "N/A" else pipesize_input

# Pressure Units Adjustments
if outlet_units == "in wc":
    outlet_input *= 1/28
elif outlet_units == "bar":
    outlet_input *= 14.5
if inlet_units == "bar":
    inlet_input *= 14.5

opp_input = input("Do you require overpressure protection? (y/n): ").lower()
partial = False
irv_input = 0
if opp_input == "y":
    opp_pref = input("If applicable should the program prioritize sizing with IRV or default to monitor regulator sizing? (irv/mon) ").lower()
    if opp_pref == "irv":
        irv_input = float(input("IRV protect downstream pressure to: "))
        irv_lim = irv_input - outlet_input
        opp_type = "IRV"
    else:
        opp_type = "Monitor"
else:
    partial_input = input("If applicable, select regulator with IRV for partial overpressure protection? (y/n): ")
    partial = True if partial_input == "y" else False
    opp_type = "IRV" if partial else "None"

higheff_input = input("Is this feeding a generator or high-efficiency boiler? (y/n): ").lower()
if higheff_input == "y":
    pload = float(input("What percent of the total load is feeding a generator or high-efficiency boiler: "))
    if pload < 0 or pload > 100:
        print("")
        print("Error: Percentage must be between 0-100")
        print("")
        exit()
    pload *= 0.01
else:
    pload = 0
oversizeby = 1.2 + (0.8 * pload)
oversize_percent = (oversizeby - 1) * 100

# Other Gasses
# -----------------------------
gastype_input = input("Other gas (no, propane, other): ")
if gastype_input == "other":
    sg = float(input("Enter specific gravity: "))
    gastypemult = (0.6 / sg) ** 0.5
    if gastypemult > 1:
        gastypemult = 1
    print("")
    print("Contact USG for regulator compatibility with gasses other than methane or propane")
elif gastype_input == "propane":
    gastypemult = 0.63
else:
    gastypemult = 1

# Flowrate Unit Adjustments
if flowrate_units == "CMH":
    flow_rate *= 35.3147
elif flowrate_units == "BTUH":
    if gastype_input == "n":
        flow_rate *= 1/1000
    elif gastype_input == "propane":
        flow_rate *= 1/2516
    else:
        print("Enter gas load/flow rate in CFH or CMH when using other gasses")
